def derive_voiced_consonant(base_sign):
    """Simulate deriving a voiced consonant from an unvoiced base sign."""
    voiced_map = {
        'ka': 'ga', 'ki': 'gi', 'ku': 'gu', 'ke': 'ge', 'ko': 'go',
        'sa': 'za', 'shi': 'ji', 'su': 'zu', 'se': 'ze', 'so': 'zo',
        'ta': 'da', 'chi': 'ji', 'tsu': 'zu', 'te': 'de', 'to': 'do',
        'ha': 'ba', 'hi': 'bi', 'fu': 'bu', 'he': 'be', 'ho': 'bo'
    }
    return voiced_map.get(base_sign, base_sign)

# Example usage
print(derive_voiced_consonant('ka'))  # Output: 'ga'
print(derive_voiced_consonant('sa'))  # Output: 'za'
